sections.example:
public class Main {
    public static void main(String[] args) {
        int a = 7, b = 2;
        System.out.println(a / b);            // 3 (integer division)
        System.out.println((double) a / b);   // 3.5

        double x = 9.99;
        int truncated = (int) x;
        System.out.println(truncated);        // 9

        int i = 100;
        long l = i;          // implicit widening
        System.out.println(l); // 100
    }
}

