public class Main {
    public static void main(String[] args) {
        Integer num = null;
        System.out.println(num == null);  // true

        String s = "123";
        int parsed = Integer.parseInt(s);
        System.out.println(parsed + 1);   // 124

        Integer boxed = 42;  // auto-boxing
        int unboxed = boxed; // auto-unboxing
        System.out.println(unboxed);      // 42
    }
}

